import{_ as t,o as i,c as a,an as r}from"./chunks/framework.CoEzzX3i.js";const p=JSON.parse('{"title":"LoweredDistributions","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),s={name:"index.md"};function o(n,e,l,d,h,c){return i(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="LoweredDistributions" tabindex="-1">LoweredDistributions <a class="header-anchor" href="#LoweredDistributions" aria-label="Permalink to &quot;LoweredDistributions {#LoweredDistributions}&quot;">​</a></h1><p><em>A distribution-lowering hub: <code>lower</code> maps a <code>Distributions.Distribution</code> onto a backend-agnostic dynamical-systems representation.</em></p><h2 id="Why-LoweredDistributions?" tabindex="-1">Why LoweredDistributions? <a class="header-anchor" href="#Why-LoweredDistributions?" aria-label="Permalink to &quot;Why LoweredDistributions? {#Why-LoweredDistributions?}&quot;">​</a></h2><p>A delay distribution and a compartmental model are two views of the same thing: <code>Gamma(3, 1.5)</code> is a waiting time, and also three exponential compartments in series, each left at rate <code>1/1.5</code>. <code>lower</code> maps any <code>Distribution</code> onto that dynamical-systems view, fitting one by moment-matching where no exact chain exists, and four weak-dependency extensions turn the result into a Catalyst, SciMLBase, JumpProcesses, or AlgebraicPetri object. See the <a href="/previews/PR63/getting-started/tutorials/lowering-backends#lowering-backends">lowering tutorial</a> for the full hierarchy, the fitting criterion, and a worked example across all four backends.</p><h2 id="Getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#Getting-started" aria-label="Permalink to &quot;Getting started {#Getting-started}&quot;">​</a></h2><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LoweredDistributions, Distributions</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">lower</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Gamma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;">ErlangChain(3 compartments)</span></span></code></pre></div><p>The <a href="/previews/PR63/getting-started/tutorials/lowering-backends#lowering-backends">tutorial</a> takes one delay through all four backends and checks each against the distribution it came from. See the <a href="https://lowereddistributions.epiaware.org/stable/" target="_blank" rel="noreferrer">documentation</a> for the full walkthrough.</p><h2 id="Where-to-learn-more" tabindex="-1">Where to learn more <a class="header-anchor" href="#Where-to-learn-more" aria-label="Permalink to &quot;Where to learn more {#Where-to-learn-more}&quot;">​</a></h2><ul><li><p><a href="https://github.com/EpiAware/LoweredDistributions.jl/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a></p></li><li><p><a href="https://github.com/EpiAware/LoweredDistributions.jl" target="_blank" rel="noreferrer">GitHub Repository</a></p></li></ul><p>&lt;!– standard-sections:start –&gt; &lt;!– MANAGED by EpiAwarePackageTools.scaffold — do not edit between the markers. These standard sections are re-rendered on every scaffold_update; edit the package-owned sections outside them, or CITATION.cff. –&gt;</p><h2 id="Contributing" tabindex="-1">Contributing <a class="header-anchor" href="#Contributing" aria-label="Permalink to &quot;Contributing {#Contributing}&quot;">​</a></h2><p>We welcome contributions and new contributors! Please open an issue or pull request on <a href="https://github.com/EpiAware/LoweredDistributions.jl" target="_blank" rel="noreferrer">GitHub</a>. This package follows <a href="https://github.com/SciML/ColPrac" target="_blank" rel="noreferrer">ColPrac</a> and the <a href="https://github.com/SciML/SciMLStyle" target="_blank" rel="noreferrer">SciML style</a>.</p><h2 id="How-to-cite" tabindex="-1">How to cite <a class="header-anchor" href="#How-to-cite" aria-label="Permalink to &quot;How to cite {#How-to-cite}&quot;">​</a></h2><p>If you use LoweredDistributions in your work, please cite it. Citation metadata lives in <a href="https://github.com/EpiAware/LoweredDistributions.jl/blob/main/CITATION.cff" target="_blank" rel="noreferrer"><code>CITATION.cff</code></a>, which GitHub renders as a &quot;Cite this repository&quot; button on the repository page.</p><h2 id="Code-of-conduct" tabindex="-1">Code of conduct <a class="header-anchor" href="#Code-of-conduct" aria-label="Permalink to &quot;Code of conduct {#Code-of-conduct}&quot;">​</a></h2><p>Please note that the LoweredDistributions project is released with a <a href="https://github.com/EpiAware/.github/blob/main/CODE_OF_CONDUCT.md" target="_blank" rel="noreferrer">Contributor Code of Conduct</a>. By contributing, you agree to abide by its terms. &lt;!– standard-sections:end –&gt;</p>`,17)])])}const b=t(s,[["render",o]]);export{p as __pageData,b as default};
